-- Enrichment marathon batch: Data Miner, Data Rescue, Dataimporter.io, Datalore, Datarails, DataStax, DataVisor, datelist.io

-- ── Data Miner ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Data Miner is a Chrome and Edge browser extension that scrapes tables and structured data from web pages and exports the results to CSV, Excel, or Google Sheets. It uses point-and-click recipes, community-shared templates for popular sites, and custom JavaScript rules to extract data without writing code. It is built and maintained by Software Innovation Lab LLC of Seattle, Washington.$q$, short_description),
  pricing_model = COALESCE($q$Freemium subscription, billed monthly by number of pages scraped$q$, pricing_model),
  starting_price = COALESCE($q$Free for up to 500 pages per month; paid plans start at 19.99 USD per month$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE($q$Small, privately held company (exact headcount not publicly disclosed)$q$, company_size),
  headquarters = COALESCE($q$Seattle, Washington, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Data Miner Review 2026: Pricing and Features$q$, seo_title),
  seo_meta_description = COALESCE($q$Data Miner is a Chrome and Edge extension for scraping web tables and data into CSV or Excel. See 2026 pricing, features, pros, cons and FAQs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Data Miner is a browser extension for Google Chrome and Microsoft Edge that lets users extract, or scrape, structured data from web pages and convert it into a CSV file, an Excel spreadsheet, or a Google Sheet. It is developed and maintained by Software Innovation Lab LLC, a small software company based in Seattle, Washington. Data Miner is aimed at non-technical users such as sales, marketing, research, and e-commerce professionals who need to pull data such as product listings, prices, reviews, contact information, or search results from websites without writing custom scraping code. The core mechanism behind Data Miner is the 'recipe', a saved set of extraction rules tied to a specific website or page pattern. Data Miner ships with a large public library of community-contributed and company-maintained recipes for popular sites including major e-commerce marketplaces, business directories, job boards, and social networks, so many users can click a button and immediately pull data from a supported site. For sites without a pre-built recipe, Data Miner provides a point-and-click recipe editor: users click on the data they want, such as a price, a name, or a table column, and Data Miner infers a reusable rule they can save, edit, and share. Power users can extend recipes with custom JavaScript to clean, transform, or filter scraped values before export, for example stripping currency symbols or parsing an email address out of a block of text. Beyond single-page scraping, Data Miner supports multi-page automation. It can follow next-page links, paginated search results, or infinite-scroll patterns to crawl through many pages in one run, and it can fill in web forms from a CSV of input values to automate repetitive lookups. It can also scrape data that sits behind a login or inside a private intranet, because it runs inside the user's own authenticated browser session rather than through an external crawler with no access to that session. Exports go to local CSV or Excel files, or directly into a connected Google Sheet, which keeps a running spreadsheet updated as new scrapes are run. Data Miner uses a freemium, page-count-based pricing model. The free plan allows up to 500 page scrapes per month with access to public recipes and basic automation, but restricts access to some domains and to private recipes. Paid plans, Solo, Small Business, Business, and Business Plus, unlock private recipe creation, unrestricted domain access, custom JavaScript, Google Sheets integration, and email support, and scale by monthly page-scrape limits from 500 pages up to 9,000 pages, priced from about 19.99 USD to 200 USD per month. Larger organizations that need higher volumes, server-side scraping instead of local browser scraping, or long-term contracts can request custom Enterprise pricing. Because Data Miner runs entirely inside the browser and relies on the user's own IP address and session, it does not include built-in proxy rotation, a hosted scraping API, or scheduled cloud-based crawls, functionality found in dedicated scraping platforms. This makes it well suited to ad hoc, occasional, or moderate-volume data pulls by an individual user, but less suited to large-scale, automated, unattended scraping pipelines. Typical use cases include competitive price monitoring, lead list building from directories, real estate or job listing aggregation, and pulling structured tables out of government or research websites for analysis. Reviewers generally rate it highly for ease of use and accuracy on supported sites, while noting the lack of proxies, API access, and scale as the main limitations for heavier scraping workloads.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'c9031180-f3be-4ace-8d4c-cae03b1b7546';

