-- ── Data Rescue ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Data Rescue is a data recovery application for Mac and Windows made by Prosoft Engineering, used to recover deleted, formatted, or corrupted files from hard drives, SSDs, and removable media. It scans a drive, lets users preview recoverable files before paying, and then restores them to a separate destination. Prosoft Engineering has published the Data Rescue product line since 2002.$q$, short_description),
  pricing_model = COALESCE($q$One-time and annual license options, plus a free scan-and-preview trial$q$, pricing_model),
  starting_price = COALESCE($q$Free trial recovers up to 1GB; paid Standard license starts at 79 USD for 30 days of unlimited recovery$q$, starting_price),
  founded_year = COALESCE(1985, founded_year),
  company_size = COALESCE($q$Small, privately held company (exact headcount not publicly disclosed)$q$, company_size),
  headquarters = COALESCE($q$Pleasanton, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Data Rescue Review 2026: Pricing, Features, Pros and Cons$q$, seo_title),
  seo_meta_description = COALESCE($q$Data Rescue by Prosoft Engineering recovers deleted files on Mac and Windows. See 2026 pricing plans, key features, pros, cons and FAQs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Data Rescue is a data recovery software application published by Prosoft Engineering, Inc., a company founded in 1985 and based in Pleasanton, California. Prosoft has sold versions of Data Rescue since 2002, and the product has gone through multiple major versions, with Data Rescue 6 being the current generation available for both macOS and Windows from a single license. Data Rescue is designed for consumers, IT professionals, and small businesses who need to recover files that were accidentally deleted, lost when a drive was formatted or reformatted, or made inaccessible because a drive will not mount, will not boot, or has developed file system corruption. The recovery workflow follows three steps: scan, preview, and recover. Users choose between a Quick Scan, intended for drives that will not boot or mount and that searches for a known, previously cataloged file system structure, and a Deep Scan, a more thorough sector-by-sector search used for drives that have been reformatted or that have more extensive data loss. Data Rescue can recover files from internal hard disk drives and solid-state drives, external drives, USB flash drives, SD and Compact Flash cards, and other removable media, and it supports the NTFS, APFS, HFS+, FAT, and exFAT file systems used by Windows and Mac computers. A feature called FileIQ lets the software learn to recognize new or unlisted file signatures during a scan, which helps it identify file types that are not in its standard built-in list. Before paying for a license, users can preview the names and, for many file types, the contents of recoverable files, so they can judge whether a paid recovery is worthwhile. Data Rescue's Advanced Mode adds tools aimed at more technical users and IT professionals, including a hex viewer for inspecting raw disk data, a secure erase function, the ability to save and manage as many as 15 separate scan sessions, support for RAID 0 and JBOD arrays, a virtual RAID simulation feature for rebuilding arrays before committing to a recovery, and low-level allocation block layout analysis. On the Mac, Data Rescue can also build a bootable recovery drive, which allows a technician to boot a Mac from external media when its internal startup drive has failed, and scan or recover files without ever writing to the failing drive itself. The software recognizes more than 100 distinct file types out of the box, spanning documents such as PDF, Word, Excel, PowerPoint, and QuickBooks files, images including TIFF, PNG, RAW camera formats, and Adobe Illustrator files, and audio formats such as MP3, WAV, AAC, and Logic Pro session files. Pricing follows a tiered model. Every user can run a free trial that scans and previews an entire drive and recovers up to 1GB of data at no cost, which is enough to test whether important files are recoverable before paying. Beyond the trial, a Standard license, priced at 79 USD, unlocks unlimited data recovery for 30 days, making it suited to a single, one-time recovery job. For users or professionals who expect to need data recovery repeatedly, a Professional license, priced at roughly 399.96 USD per year, provides unlimited recoveries across drives and devices for the length of the subscription, and one license can be used across both the Mac and Windows builds of the software. Data Rescue requires a working secondary storage device to hold recovered files, since recovered data should never be written back to the same drive being scanned, and the current Mac build supports Apple Silicon Macs as well as a documented range of macOS versions. Prosoft Engineering also sells Drive Genius, a separate Mac disk maintenance and optimization utility, and offers paid, hands-on data recovery services for customers with especially difficult cases such as physically damaged drives or failed RAID arrays that self-service software cannot resolve.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'b73f5754-ca55-4c7c-b69e-ff5322f97d7c';

