-- ── Datalore ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Datalore is a cloud-based, Jupyter-compatible data science notebook environment made by JetBrains, supporting Python, R, Kotlin, and SQL with real-time collaborative editing, AI-assisted coding, and one-click interactive reports. It is available as a managed cloud service or as a self-hosted On-Premises deployment for teams with strict data governance needs. JetBrains first released Datalore in November 2018.$q$, short_description),
  pricing_model = COALESCE($q$Freemium subscription with a free Cloud tier, a paid Cloud team tier, and custom On-Premises licensing$q$, pricing_model),
  starting_price = COALESCE($q$Free Cloud plan available; paid Cloud plans and On-Premises pricing available on request$q$, starting_price),
  founded_year = COALESCE(2018, founded_year),
  company_size = COALESCE($q$JetBrains employs over 1000 people worldwide (Datalore team size not separately disclosed)$q$, company_size),
  headquarters = COALESCE($q$Prague, Czech Republic (JetBrains headquarters)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Datalore by JetBrains Review 2026: Pricing and Features$q$, seo_title),
  seo_meta_description = COALESCE($q$Datalore is JetBrains' collaborative, Jupyter-compatible data science notebook. See 2026 pricing, AI coding features, pros, cons and FAQs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Datalore is a cloud-based data science notebook platform built by JetBrains, the software company best known for developer tools such as IntelliJ IDEA, PyCharm, and Kotlin. JetBrains first launched Datalore in November 2018 as a web-based environment for data analysis and machine learning in Python, and has since expanded it into a broader, Jupyter-compatible collaborative workspace that also supports R, Kotlin, and SQL. JetBrains is headquartered in Prague, Czech Republic, and Datalore is offered both as a JetBrains-managed cloud product and as a self-hosted On-Premises deployment for organizations that need to keep notebooks and data inside their own infrastructure. Datalore's core proposition is real-time collaboration on notebooks that remain compatible with the standard Jupyter format, so teams can co-edit a notebook simultaneously the way they would co-edit a shared document, see each other's cursors and changes live, and share notebooks by link or email invitation with view-only or edit-level access. Each notebook runs in its own isolated compute environment with an integrated environment and package manager, built-in version history, and integrated cloud storage, removing the need for a data scientist to separately manage virtual environments, requirements files, or storage buckets. Datalore AI, the platform's AI coding assistant, helps users write Python, SQL, and R code faster, generate explanatory text around findings, and automatically fix code errors, aiming to speed up both exploratory analysis and the write-up of results. A one-click interactive report feature turns an ordinary analysis notebook into a shareable, presentation-style document that hides code cells from the audience while keeping charts, tables, and narrative text interactive, aimed at analysts who need to hand off findings to non-technical stakeholders without exporting to a separate tool such as a slide deck. Datalore is priced on a freemium basis. The Cloud Free plan is aimed at individual users and students, and includes unlimited notebooks with real-time collaboration, coding assistance, the ability to run two notebooks in parallel, one shared workspace, one interactive report, notebook export, and API access, backed by a resource allowance of 120 CPU-small machine hours and 10GB of cloud storage. The paid Cloud plan, aimed at teams and advanced analysts, adds Datalore AI, unlimited parallel notebooks, a reactive execution mode that automatically re-runs dependent cells when inputs change, full version history, unlimited database connections, unlimited reports and workspaces, scheduled notebook runs, and team management tools, with a resource allowance of 750 CPU-large machine hours per team member per month, access to GPU-backed machines, and 20GB of storage plus additional support; exact monthly or annual pricing for the Cloud plan is provided on request rather than published as a flat rate. A 14-day free trial of the Cloud product is available with a cap of three users and limited compute. Organizations that need to keep code and data entirely within their own network can license Datalore On-Premises, a self-hosted version with unlimited core features, internal usage plans configurable by an administrator, and full control over compute resources; On-Premises pricing is quote-based. Because Datalore is Jupyter-compatible, teams already using Jupyter notebooks, JupyterLab, or Google Colab can generally import and export their existing notebook files with minimal friction. Typical users include data science teams that want managed, governed collaboration without running their own JupyterHub infrastructure, analytics teams producing recurring reports for business stakeholders, and organizations in regulated industries that need the on-premises option to keep data science workloads inside their own security perimeter.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '9471901f-8ac1-4efa-abb6-76295096241c';

