INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b756f9f4-d0fd-4019-94bf-65b792969130', $q$What is datelist.io used for?$q$, $q$datelist.io is used by service businesses to let customers book appointments or reservations online at any time, with automated reminders and payment collection.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b756f9f4-d0fd-4019-94bf-65b792969130', $q$How much does datelist.io cost?$q$, $q$datelist.io is sold as a single, all-inclusive plan starting at 9 EUR per month.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b756f9f4-d0fd-4019-94bf-65b792969130', $q$Does datelist.io send appointment reminders?$q$, $q$Yes, it can automatically send SMS and email confirmation and reminder messages before each appointment.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b756f9f4-d0fd-4019-94bf-65b792969130', $q$Can customers pay online when booking with datelist.io?$q$, $q$Yes, datelist.io supports collecting payment or deposits at the time of booking through multiple payment methods.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b756f9f4-d0fd-4019-94bf-65b792969130', $q$What industries does datelist.io support?$q$, $q$datelist.io serves salons, restaurants, consultants, cleaning companies, event organizers, and other appointment-based businesses.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b756f9f4-d0fd-4019-94bf-65b792969130', $q$Does datelist.io integrate with other business tools?$q$, $q$Yes, it connects to CRM, invoicing, and newsletter tools, and is available through the Slack and Pipedrive marketplaces.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b756f9f4-d0fd-4019-94bf-65b792969130', $q$Who makes datelist.io?$q$, $q$datelist.io is made by ACL Software SRL, a company based in Temploux, Belgium.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b756f9f4-d0fd-4019-94bf-65b792969130', $q$Is datelist.io available in English?$q$, $q$Yes, datelist.io's platform and help center content are available in both English and French.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b756f9f4-d0fd-4019-94bf-65b792969130', $q$Salon and spa reservations$q$, $q$Let clients book haircuts, treatments, or spa sessions online at any hour.$q$, $q$Salon and spa owners$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b756f9f4-d0fd-4019-94bf-65b792969130', $q$Restaurant table reservations$q$, $q$Manage table bookings and reduce no-shows with automated reminders.$q$, $q$Restaurant managers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b756f9f4-d0fd-4019-94bf-65b792969130', $q$Consultant and coach session scheduling$q$, $q$Allow clients to book paid consulting or coaching sessions directly online.$q$, $q$Independent consultants$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b756f9f4-d0fd-4019-94bf-65b792969130', $q$Home service appointment booking$q$, $q$Schedule cleaning or other home service visits with calendar sync and reminders.$q$, $q$Home service business owners$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b756f9f4-d0fd-4019-94bf-65b792969130', $q$Standard$q$, $q$9 EUR$q$, $q$monthly$q$, NULL, $q$["online booking page","automated reminders","calendar sync","online payment collection","custom branding"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b756f9f4-d0fd-4019-94bf-65b792969130', $q$booking-and-reminders$q$, $q$Booking, Reminders, and Payment$q$, 2, ARRAY[$q$Customers book an available appointment directly from a business's website or social media links at any hour, and once a booking is made, datelist.io can automatically send confirmation and reminder messages by SMS or email to help reduce no-shows and last-minute cancellations.$q$, $q$The platform can also collect payment or a deposit at the time of booking, supporting multiple payment methods including card payments and Bancontact, and it synchronizes two-way with the business owner's personal calendar to avoid double-booking.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b756f9f4-d0fd-4019-94bf-65b792969130', $q$branding-and-integrations$q$, $q$Branding and Business Tool Integrations$q$, 2, ARRAY[$q$Businesses can customize the booking page's colors and style directly from the web platform so it matches their existing website rather than looking like a generic third-party form.$q$, $q$datelist.io connects to CRM, invoicing, and newsletter tools, and is listed on the Slack and Pipedrive marketplaces, letting a booking trigger downstream workflows such as adding a client to a mailing list or generating an invoice.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b756f9f4-d0fd-4019-94bf-65b792969130', $q$simple-pricing$q$, $q$A Single, Flat-Rate Pricing Plan$q$, 2, ARRAY[$q$Rather than offering multiple tiers gated by feature or user count, datelist.io is sold as one all-inclusive subscription starting at 9 EUR per month, which the company states covers support with no hidden fees.$q$, $q$This flat pricing approach is aimed at small and solo service businesses that want a predictable monthly cost without needing to compare which features are locked behind higher tiers.$q$]::text[], 2);
